import subprocess

from setuptools import setup, find_packages

def get_requirements(file_path):
    with open(file_path) as f:
        requirements = [line.strip() for line in f if not line.startswith('#')]
        return requirements

def run_pip(command):
    process = subprocess.Popen(["pip", "install"] + command, stdout=subprocess.PIPE)
    output, _ = process.communicate()
    return output.decode().strip()

REQUIREMENTS_FILE = 'requirements.txt'
EXTRA_REQUIREMENTS = {
    'dev': ['pytest', 'coverage'],
}

install_requires = get_requirements(REQUIREMENTS_FILE)
extra_reqs = {}
for dep_name, deps in EXTRA_REQUIREMENTS.items():
    extra_reqs[dep_name] = get_requirements(f'{REQUIREMENTS_FILE}_{dep_name}.txt') + deps

setup(
    name='my_project',
    version='0.1',
    packages=find_packages(),
    install_requires=install_requires,
    extras_require=extra_reqs,
)

for extra in EXTRA_REQUIREMENTS.values():
    for reqs in extra:
        run_pip(reqs)